import{_ as i,aa as l,o as p,c as t,a,V as n,U as o,Y as r}from"./chunks/framework.CgeyQwv7.js";import"./chunks/theme.BlWxUSg9.js";const x=JSON.parse('{"title":"Jenkins流水线部署Java项目","description":"Docker部署Jenkins并通过Jenkinsfile部署Java Spring项目","frontmatter":{"title":"Jenkins流水线部署Java项目","category":["Jenkins"],"tag":["Jenkinsfile","流水线","Java","Pipeline"],"description":"Docker部署Jenkins并通过Jenkinsfile部署Java Spring项目","date":"2023-02-13T16:42:00.000Z","updated":"2023-02-20T15:56:00.000Z","cover":"devicon:jenkins"},"headers":[],"relativePath":"articles/devops/ci-cd/jenkins/JavaFlowline.md","filePath":"articles/devops/ci-cd/jenkins/JavaFlowline.md"}'),c={name:"articles/devops/ci-cd/jenkins/JavaFlowline.md"};function k(m,s,d,h,g,u){const e=l("SmallCard");return p(),t("div",null,[s[0]||(s[0]=a("h2",{id:"jenkins流水线部署java项目",tabindex:"-1"},[n("Jenkins流水线部署Java项目 "),a("a",{class:"header-anchor",href:"#jenkins流水线部署java项目","aria-label":"Permalink to “Jenkins流水线部署Java项目”"},"​")],-1)),s[1]||(s[1]=a("h3",{id:"参考资料",tabindex:"-1"},[n("参考资料 "),a("a",{class:"header-anchor",href:"#参考资料","aria-label":"Permalink to “参考资料”"},"​")],-1)),o(e,{cards:[{title:"流水线",desc:"TeamCity服务器 - 强大的持续集成和持续交付，开箱即用",logo:"https://www.jenkins.io/apple-touch-icon.png",link:"https://www.jenkins.io/zh/doc/book/pipeline/"},{title:"流水线语法",desc:"TeamCity服务器 - 强大的持续集成和持续交付，开箱即用",logo:"https://www.jenkins.io/apple-touch-icon.png",link:"https://www.jenkins.io/zh/doc/book/pipeline/syntax/"}]}),s[2]||(s[2]=r(`<h3 id="部署jenkins到docker" tabindex="-1">部署jenkins到docker <a class="header-anchor" href="#部署jenkins到docker" aria-label="Permalink to “部署jenkins到docker”">​</a></h3><p><a href="https://blog.crudclass.com/2023/02/13/docker/Jenkins/" target="_blank" rel="noreferrer">参考改文章</a></p><h3 id="配置jenkins" tabindex="-1">配置Jenkins <a class="header-anchor" href="#配置jenkins" aria-label="Permalink to “配置Jenkins”">​</a></h3><blockquote><p>需要安装docker插件<a href="https://plugins.jenkins.io/docker-plugin/" target="_blank" rel="noreferrer">Docker插件介绍</a>,可以通过jenkins自动安装插件Manage Jenkins-&gt;Plugin Manage-&gt;installed plugins也可以手动安装该插件Manage Jenkins-&gt;Plugin Manage-&gt;Advanced settings-&gt;Deploy Plugin,将<a href="https://plugins.jenkins.io/docker-plugin/#releases" target="_blank" rel="noreferrer">这里</a>下载最新的插件或者其他版本的该插件进行上传安装 推荐更换插件下载源Manage Jenkins-&gt;Plugin Manage-&gt;Advanced settings-&gt;Update Site-&gt;<a href="https://mirrors.tuna.tsinghua.edu.cn/jenkins/updates/update-center.json" target="_blank" rel="noreferrer">https://mirrors.tuna.tsinghua.edu.cn/jenkins/updates/update-center.json</a></p></blockquote><p>如图点击 New Item</p><p><img src="https://images.crudclass.com/img/202302172039139.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图一" loading="lazy"></p><p>如图先输入项目名称,选择Pipeline然后点击ok</p><p><img src="https://images.crudclass.com/img/202302172011941.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图二" loading="lazy"></p><p>然后依次如下图操作</p><ul><li>Description:输入项目描述</li><li>Pipeline-&gt;Definition:选择Pipeline script from SCM</li><li>SCM:选择git <ul><li>Repositories <ul><li>Repository URL:git地址</li><li>Credentials:选择git账户</li></ul></li><li>Branches to build <ul><li>Branch Specifier (blank for &#39;any&#39;):选择分支例如<em>/dev;</em>/master</li><li>Repository browser:选择自动(AUTO)</li></ul></li><li>Script Path:输入Jenkinsfile文件地址,存放在项目根目录下直接填写Jenkinsfile即可,如果文件名发生改动,也请将此处修改为文件名称</li></ul></li><li>最后点击保存即可</li></ul><p><img src="https://images.crudclass.com/img/202302172022637.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图三" loading="lazy"></p><p><img src="https://images.crudclass.com/img/202302172023406.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图四" loading="lazy"></p><p><img src="https://images.crudclass.com/img/202302172023076.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图五" loading="lazy"></p><p>添加git账号</p><p><img src="https://images.crudclass.com/img/202302172050740.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图六" loading="lazy"></p><p>点击Add</p><p><img src="https://images.crudclass.com/img/202302172049866.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图七" loading="lazy"></p><p>如下</p><ul><li>Kind:选择Username with password,当然也可以选择其他方式 <ul><li>Scope:Global</li><li>Username:git账户</li><li>Password:git对应账户密码</li><li>Treat username as secret:是否屏蔽用户名</li><li>ID:一个内部唯一 ID，通过它可以从作业和其他配置中识别这些凭据。通常留空，在这种情况下将生成一个 ID，这适用于使用可视化表单创建的作业。在使用脚本配置中的凭据时明确指定很有用。</li><li>Description:帮助区分相似凭据的可选描述。</li></ul></li></ul><p><img src="https://images.crudclass.com/img/202302172049994.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图八" loading="lazy"></p><h3 id="编写jenkinsfile" tabindex="-1">编写Jenkinsfile <a class="header-anchor" href="#编写jenkinsfile" aria-label="Permalink to “编写Jenkinsfile”">​</a></h3><p>在项目根目录下新建Jenkinsfile文件</p><blockquote><p>Jenkinsfile名称需要与上面 Script Path使用的名称相同</p></blockquote><p>内容如下</p><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pipeline {</span></span>
<span class="line"><span>    agent any</span></span>
<span class="line"><span>    options {</span></span>
<span class="line"><span>        timeout(time: 15, unit: &#39;MINUTES&#39;)</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    stages {</span></span>
<span class="line"><span>        stage (&#39;Start Package&#39;){</span></span>
<span class="line"><span>            options { skipDefaultCheckout() }</span></span>
<span class="line"><span>            agent {</span></span>
<span class="line"><span>                docker {</span></span>
<span class="line"><span>                    reuseNode &#39;true&#39;</span></span>
<span class="line"><span>                    image &#39;maven:3.8.6-openjdk-8-slim&#39;</span></span>
<span class="line"><span>                    args &#39;-v /tool/maven/.m2:/root/.m2 -v /tool/maven/conf:/usr/share/maven/conf&#39;</span></span>
<span class="line"><span>                }</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>            steps {</span></span>
<span class="line"><span>                sh &#39;mvn clean package -Dmaven.test.skip=true -P prod&#39;</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        stage(&#39;Docker build and run&#39;) {</span></span>
<span class="line"><span>            options { skipDefaultCheckout() }</span></span>
<span class="line"><span>            steps {</span></span>
<span class="line"><span>                sh &#39;docker stop ws-mechanism|| true &amp;&amp; docker rm ws-mechanism || true &amp;&amp; docker rmi ws-mechanism:latest || true &#39;</span></span>
<span class="line"><span>                sh &#39;docker build -t ws-mechanism:latest -f Dockerfile .&#39;</span></span>
<span class="line"><span>                sh &#39;docker run -itd --restart=always --network=share_net -p 16060:16060 --name ws-mechanism -v /logs/ws-mechanism:/ws-mechanism/log.path_IS_UNDEFINED ws-mechanism:latest&#39;</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        stage(&#39;Docker clean&#39;) {</span></span>
<span class="line"><span>            options { skipDefaultCheckout() }</span></span>
<span class="line"><span>            steps {</span></span>
<span class="line"><span>                sh &#39;echo y|docker image prune&#39;</span></span>
<span class="line"><span>                sh &#39;echo y|docker volume prune&#39;</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>解释1:</p><ol><li>timeout:设置流水线运行的超时时间, 在此之后，Jenkins将中止流水线。例如: <code>options { timeout(time: 1, unit: &#39;HOURS&#39;) }</code></li><li>skipDefaultCheckout:在<code>agent</code> 指令中，跳过从源代码控制中检出代码的默认情况。例如: <code>options { skipDefaultCheckout() }</code></li><li>docker:使用给定的容器执行流水线或阶段 <ol><li>reuseNode:一个布尔值, 默认为false。 如果是true, 则在流水线的顶层指定的节点上运行该容器, 在同样的工作区, 而不是在一个全新的节点上.</li><li>image:镜像名称 <ol><li>maven:3.8.6-openjdk-8-slim:使用和开发环境相同的版本镜像</li></ol></li><li>args:参数，该参数可能包含直接传递到 docker run 调用的参数 <ol><li>-v /tool/maven/.m2:/root/.m2 -v /tool/maven/conf:/usr/share/maven/conf:挂载maven的配置文件和下载的jar包,提升编译速度</li></ol></li></ol></li><li>steps:执行的命令</li></ol><p>解释2:</p><ol><li>mvn clean package -Dmaven.test.skip=true -P prod:打jar包</li><li>sh &#39;docker stop ws-mechanism|| true &amp;&amp; docker rm ws-mechanism || true &amp;&amp; docker rmi ws-mechanism:latest || true &#39;:停止并删除镜像</li><li>sh &#39;docker build -t ws-mechanism:latest -f Dockerfile .&#39;通过Dockerfile打包image</li><li>sh &#39;docker run -itd --restart=always --network=share_net -p 16060:16060 --name ws-mechanism -v /logs/ws-mechanism:/ws-mechanism/log.path_IS_UNDEFINED ws-mechanism:latest&#39;:运行docker run</li></ol><p>Dockerfile内容如下</p><div class="language-Dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">Dockerfile</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> moxm/java:1.8-full</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mkdir -p /ws-mechanism</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WORKDIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /ws-mechanism</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ARG</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> JAR_FILE=./ws-admin/target/ws-admin.jar</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${JAR_FILE} app.jar</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">EXPOSE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 16060</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ENV</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> TZ=Asia/Shanghai</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sleep 30; java -jar app.jar</span></span></code></pre></div><h3 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to “启动”">​</a></h3><p>进入到刚刚Jenkins创建的项目点击Build Now进行首次构建,或者打开Blue Ocean进行构建,图示为打开Blue Ocean</p><p><img src="https://images.crudclass.com/img/202302201542674.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图九" loading="lazy"></p><p>通过点击<strong>运行</strong>进行构建,构建成功如图,每一个stage都是一个节点,该图示通过打两次不同环境的配置文件,在同一个docker中部署两个不同环境的相同项目</p><p><img src="https://images.crudclass.com/img/202302201544778.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图十" loading="lazy"></p><p>构建失败可以通过如图方式进行查看</p><p><img src="https://images.crudclass.com/img/202302201551702.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图十一" loading="lazy"></p><p><img src="https://images.crudclass.com/img/202302201550018.png?x-oss-process=image/auto-orient,1/interlace,1/quality,q_90/watermark,type_ZmFuZ3poZW5na2FpdGk,size_20,text_YmxvZy5jcnVkY2xhc3MuY29t,color_012EA5,shadow_0,t_100,g_se,x_10,y_10" alt="图十二" loading="lazy"></p><p>该错误为Jenkinsfile语法错误</p><h3 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to “结语”">​</a></h3><p>每次提交 Git 后，通过登录 Jenkins 手动构建新的镜像从而运行项目，也可以通过自动方式检测到 Git 提交就进行重新部署，需要修改项目配置。</p>`,42))])}const w=i(c,[["render",k]]);export{x as __pageData,w as default};
